import re

def esc(s):
    return s.replace('\\','\\\\').replace('"','\\"').replace('\n','\\n').replace('\r','')

def q(id_,exam,lec,question,opts,ans,exp):
    o=','.join(f'"{esc(x)}"' for x in opts)
    return f'  {{id:"{id_}",exam:"{exam}",lecture:"{esc(lec)}",q:"{esc(question)}",options:[{o}],answer:{ans},explanation:"{esc(exp)}"}}'

L1="Lec 1 — Introduction"
L2="Lec 2 — Dosage Forms"
L3="Lec 3 — Routes of Administration"
L4="Lec 4 — Pharmacodynamics"
L5="Lec 5 — Pharmacokinetics"
L6="Lec 6 — Factors & ADR"
L7="Lec 7 — Drug Interactions"
L8="Lec 8 — Toxicology"
L9="Lec 9 — IV Fluids"

mid1=[
q("mid11","mid1",L1,"What does pharmacokinetics (PK) refer to?",["What the drug does to the body","Mechanism of drug action","What the body does to the drug (ADME)","Drug toxicity"],2,"PK = what the body does to the drug: Absorption, Distribution, Metabolism, Excretion. PD = what the drug does to the body."),
q("mid12","mid1",L1,"Pharmacodynamics deals with:",["Absorption","Elimination","Metabolism","Mechanism of action"],3,"PD = what the drug does to the body — mechanisms of action, receptor binding, pharmacological effects."),
q("mid13","mid1",L1,"A drug marketed under its non-proprietary name is referred to as its:",["Chemical name","Generic name","Brand name","Trade name"],1,"The generic (INN/non-proprietary) name is the official universal name. Chemical name describes the molecule; brand/trade name is the manufacturer's commercial name."),
q("mid14","mid1",L1,"Generic drugs must have:",["Same active ingredient and bioequivalence","Same brand name","Same price","Same packaging"],0,"By regulation, a generic must contain the same active ingredient and demonstrate bioequivalence (same rate/extent of absorption) as the branded reference product."),
q("mid15","mid1",L1,"Phase I clinical trials primarily assess:",["Marketing","Efficacy","Comparison with placebo","Safety"],3,"Phase I: first-in-human, small group of healthy volunteers, assesses safety, tolerability, dosing, PK. Phase II: efficacy. Phase III: large RCT. Phase IV: post-marketing."),
q("mid16","mid1",L1,"Which drug category is absolutely contraindicated in ALL stages of pregnancy?",["Category A","Category B","Category C","Category X"],3,"Category X: evidence of fetal abnormalities; risks clearly outweigh any benefit — absolutely contraindicated in all stages of pregnancy."),
q("mid17","mid1",L1,"OTC (over-the-counter) drugs are:",["Can be obtained without a prescription","Only available by prescription","Experimental drugs","Controlled substances"],0,"OTC drugs are safe and effective for use without medical supervision and can be purchased directly without a prescription."),
q("mid18","mid1",L1,"Which of the following is an example of a genetic factor that affects drug response?",["Acetylation status","Drug physical properties","Renal failure","Lipid solubility of drug"],0,"Acetylation status (fast vs slow acetylators) is a classic genetic polymorphism affecting metabolism of drugs like isoniazid. Renal failure is pathological; drug properties are drug-related."),
q("mid19","mid1",L1,"Which is the unwanted reaction NOT related to absorption or pharmacodynamics of drugs?",["Pharmaceutical interaction","Pharmacodynamic interaction","Pharmacokinetic interaction","None of the above"],0,"Pharmaceutical (incompatibility) interactions occur outside the body — e.g., two drugs forming a precipitate in the same IV bag. Unrelated to absorption or pharmacodynamics."),
q("mid110","mid1",L2,"A solid dosage form that produces a high local drug concentration in the oral cavity is:",["Lozenge","Tablet","Capsule","Powder"],0,"A lozenge is a flat/round/rectangular solid held in the mouth and slowly dissolved, designed to produce high local drug concentration in the oral cavity/throat."),
q("mid111","mid1",L2,"Which of the following best describes a lozenge?",["Capsule containing powder","Flat/round/rectangular tablet held in the mouth until dissolved","Effervescent tablet dissolved in water","Sustained-release tablet"],1,"Lozenges are solid dosage forms held in the mouth (not swallowed), dissolving slowly to produce a local effect in the oral cavity/pharynx."),
q("mid112","mid1",L2,"Ointments are classified as which type of dosage form?",["Solid","Liquid","Semi-solid","Gaseous"],2,"Semi-solid dosage forms include ointments (W/O emulsions), creams (O/W emulsions), gels, pastes, and suppositories, applied to skin or mucous membranes."),
q("mid113","mid1",L2,"Enteric-coated capsules dissolve in the:",["Stomach","Mouth","Intestine","Blood"],2,"Enteric coating resists the acidic stomach and only dissolves in the alkaline small intestine, protecting acid-labile drugs or drugs that irritate the gastric mucosa."),
q("mid114","mid1",L2,"Transdermal patches are mainly used for:",["Immediate effect","Diagnostic purpose","Sustained systemic effect","Local GI effect"],2,"Transdermal patches deliver drugs through the skin into systemic circulation in a slow, sustained manner, avoiding first-pass metabolism (e.g., nitroglycerin, scopolamine, nicotine)."),
q("mid115","mid1",L2,"To prolong the duration of action of a drug, which modification is used?",["Increase vascularity of absorbing area","Reduction of solubility of the drug","Administration in aqueous solution","None of the above"],1,"Reducing drug solubility slows dissolution and absorption, prolonging duration of action (e.g., depot/suspension formulations). Increasing vascularity speeds up absorption."),
q("mid116","mid1",L3,"A patient with extensive first-pass metabolism would benefit most from which route?",["Oral","Sublingual","Rectal","Intramuscular"],1,"The sublingual route allows drug absorption directly into the systemic circulation via sublingual veins, bypassing the portal circulation and hepatic first-pass metabolism (e.g., nitroglycerin)."),
q("mid117","mid1",L3,"The main advantage of the sublingual route is:",["Slow absorption","Local effect only","Prolonged duration","Bypasses first-pass metabolism"],3,"Sublingual absorption via the rich submucosal venous network drains directly into the superior vena cava, circumventing hepatic first-pass metabolism. Also allows rapid onset."),
q("mid118","mid1",L3,"Which route provides 100% bioavailability and the most rapid onset?",["Oral","Sublingual","Intravenous (IV)","Intramuscular"],2,"IV administration gives 100% bioavailability (drug placed directly into systemic circulation). Provides most rapid onset, precise dose titration, preferred in emergencies."),
q("mid119","mid1",L3,"Which route of administration is most suitable in emergencies?",["Intravenous","Oral","Rectal","Topical"],0,"IV is preferred in emergencies: 100% bioavailability, immediate action, allows rapid dose titration, can be used in unconscious patients."),
q("mid120","mid1",L3,"Which route to administer oxytocin if it needs to be titrated according to patient's need?",["IM","IV infusion","IV bolus","Subcutaneous"],1,"IV infusion allows real-time rate adjustment, providing immediate dose titration. Oxytocin for labor induction is adjusted based on uterine contractions."),
q("mid121","mid1",L3,"Intramuscular (IM) injections are contraindicated in patients receiving:",["Anticoagulants","Steroids","Insulin","Antibiotics"],0,"IM injections in anticoagulated patients risk hematoma formation because needle insertion into a vascular muscle can cause bleeding into the muscle tissue."),
q("mid122","mid1",L3,"Which property allows a drug to cross the blood-brain barrier (BBB)?",["Lipid-soluble (lipophilic) and unionized","Hydrophilic and ionized","High molecular weight","High plasma protein binding"],0,"The BBB has tight junctions with no fenestrations. Only lipophilic, unionized, small molecular weight, low protein-bound drugs can cross by passive diffusion."),
q("mid123","mid1",L3,"Some antibiotics are well absorbed but NOT effective for brain infections because they have:",["High lipid solubility","Low bioavailability","High plasma protein binding","Rapid absorption"],2,"Only free (unbound) drug can cross the BBB. A highly protein-bound antibiotic may have good systemic absorption but the bound fraction is too large to cross, leaving minimal free drug."),
q("mid124","mid1",L3,"Which drug property is LEAST likely to allow placental crossing?",["Hydrophilic and high molecular weight","Hydrophilic and low molecular weight","Lipophilic and high molecular weight","Lipophilic and low molecular weight"],0,"The placenta behaves like a lipid membrane. Drugs that cross easily are lipophilic, un-ionized, low MW. Hydrophilic + high MW = LEAST likely to cross and harm the fetus."),
q("mid125","mid1",L3,"An addict took amphetamine and has tachycardia and tremor. Amphetamine readily enters CNS and 50% is excreted unchanged. What explains this?",["Reduced metabolism","Enhanced bioavailability","Enhanced penetration to CNS (lipophilicity)","Reduced elimination by kidney"],2,"Amphetamine is highly lipophilic, allowing it to readily cross the BBB. CNS stimulation (dopamine/norepinephrine release) causes tachycardia and tremor."),
q("mid126","mid1",L4,"Drug A has lower EC50 than Drug B with same Emax. Which is more potent?",["Drug B is more potent","They cannot be compared","Drug A is more potent","They have equal potency"],2,"Potency is measured by EC50. A lower EC50 = higher potency (less drug needed for same effect). Both drugs have same Emax (same efficacy). Drug A is more potent."),
q("mid127","mid1",L4,"ED50 — the dose producing 50% of the maximum effect — is a measure of:",["Mechanism of action","Therapeutic index","Potency","Efficacy"],2,"ED50 is the standard measure of potency. Lower ED50 = higher potency. Efficacy is measured by Emax (maximum possible effect). TI = TD50/ED50."),
q("mid128","mid1",L4,"Drug A at 5 mg decreases BP the same as Drug B at 500 mg. What does this indicate?",["Drug A is 100 times more potent than Drug B","Drug A is more efficacious","Drug A is less toxic","Drug B is more effective"],0,"Both produce the same effect but Drug A needs only 5 mg vs Drug B 500 mg. Ratio = 500/5 = 100. Drug A is 100 times more potent. Says nothing about efficacy or toxicity."),
q("mid129","mid1",L4,"2 mg of Drug A gives the same therapeutic effect as 200 mg of Drug B. Regarding potency:",["Information is not enough","Drug A is more potent than Drug B","Drug B is more potent than Drug A","Same potency"],1,"Drug A requires 2 mg vs 200 mg for Drug B for the same effect → Drug A is 100x more potent. Potency is about the dose required, not the maximum effect."),
q("mid130","mid1",L4,"If an agonist can produce maximal effects and has high efficacy, it is called:",["Antagonist","Full agonist","Competitive antagonist","Partial agonist"],1,"Full agonist: high affinity + high intrinsic activity → produces MAXIMUM response (Emax). Partial agonist: cannot reach full Emax. Antagonist: no intrinsic activity."),
q("mid131","mid1",L4,"A partial agonist, when given alone, acts as an agonist. When given with a full agonist, what happens?",["Increases the effect of the full agonist","No change in effect","Reduces the effect (acts as partial antagonist)","Doubles the effect"],2,"Partial agonists have intermediate intrinsic activity. When given with a full agonist, they compete for the same receptor, displacing the full agonist and reducing the net response."),
q("mid132","mid1",L4,"Drug R produces no response alone but shifts drug S dose-response curve to the RIGHT in a PARALLEL manner WITHOUT decreasing Emax. Drug R is a:",["Inverse agonist","Noncompetitive antagonist","Partial agonist","Competitive antagonist"],3,"Hallmark of competitive antagonist: no intrinsic activity, parallel rightward shift of DRC, Emax unchanged (surmountable — can be overcome by increasing agonist dose)."),
q("mid133","mid1",L4,"Competitive antagonist effect on dose-response curve:",["Parallel rightward shift, same Emax","Leftward shift, increased Emax","Decreased Emax only","No change in curve"],0,"Competitive antagonists occupy the receptor reversibly. Increasing agonist concentration can overcome the antagonism → same Emax achievable, but more agonist needed (rightward shift = decreased apparent potency)."),
q("mid134","mid1",L4,"If an agonist is given in increasing doses without producing any effect, which type of antagonism is most likely?",["Non-competitive antagonist","Competitive antagonist","Reversible antagonist","Surmountable antagonist"],0,"A non-competitive antagonist binds to a different (allosteric) site or irreversibly, causing a decrease in Emax — no matter how much agonist is given, the maximum effect cannot be achieved."),
q("mid135","mid1",L4,"Drugs act on the same organ but different receptors and cause effects OPPOSITE to each other. This is:",["Physiological (functional) antagonism","Chemical antagonism","Competitive antagonism","Pharmacological antagonism"],0,"Physiological/functional antagonism: two drugs have opposing effects via DIFFERENT receptors on the same tissue. Example: histamine (bronchoconstriction via H1) vs epinephrine (bronchodilation via β2)."),
q("mid136","mid1",L4,"Which of the following best describes the concept of half-life (t½)?",["Time for complete elimination","Duration required for drug concentration to decrease by half","Time to peak effectiveness","Time for drug absorption"],1,"The half-life (t½) is the time required for plasma concentration to decrease by 50%. After 4-5 half-lives, ~97% of the drug is eliminated. t½ = 0.693 × Vd / Clearance."),
q("mid137","mid1",L5,"The half-life of a drug is 3 hours. How long until it is completely eliminated?",["9 hours","12 hours (4-5 half-lives)","21 hours","4 hours"],1,"A drug is considered completely eliminated after 4–5 half-lives (97–100%). For t½ = 3h: 4 × 3 = 12 hours. 5 × 3 = 15 hours. Answer closest to 4 half-lives = 12 hours."),
q("mid138","mid1",L4,"Which of the following describes TACHYPHYLAXIS?",["Rapidly developing tolerance (acute tolerance within minutes)","A synergism between two drugs","A drug with fast response","Drug interaction between similar drugs"],0,"Tachyphylaxis = rapid acute tolerance developing within minutes to hours. Different from regular tolerance (days/weeks). Example: ephedrine loses effectiveness after repeated doses."),
q("mid139","mid1",L4,"Therapeutic index (TI) formula:",["ED50/TD50","TD50/ED50","LD50/TD50","EC50/TD50"],1,"Therapeutic Index = TD50 / ED50. TD50 = toxic dose in 50% of population. ED50 = effective dose in 50%. Larger TI = safer drug. Narrow TI drugs (warfarin, digoxin) require monitoring."),
q("mid140","mid1",L4,"Which parameter is used to indicate drug safety?",["Bioavailability","Intrinsic activity","Therapeutic index","Potency"],2,"The therapeutic index measures the margin of safety between therapeutic and toxic doses. Wide TI = little risk of toxicity; narrow TI = careful dose monitoring required."),
q("mid141","mid1",L4,"A 14-year-old with allergic rhinitis is treated with loratadine (H1 blocker). Which term best describes loratadine's BINDING to the H1 receptor?",["Affinity","Potency","Maximal efficacy","Intrinsic activity"],0,"Affinity = the tendency/ability of a drug to bind to a receptor (measured by Kd). The question asks about the characteristic of binding — this is affinity. Efficacy/intrinsic activity relate to what happens after binding."),
q("mid142","mid1",L4,"Which statement explains receptor affinity?",["Maximum response achievable","Concentration of ligand causing side effect","The measure of how tightly a ligand binds to a receptor","Fraction of dose reaching circulation"],2,"Affinity is the strength of the drug-receptor interaction. High affinity = drug binds at low concentrations. Quantified by equilibrium dissociation constant (Kd); lower Kd = higher affinity."),
q("mid143","mid1",L4,"A 9-year-old with asthma uses a β2-adrenoreceptor agonist by inhalation. What type of receptor is β2?",["G protein-coupled receptor (GPCR)","Intracellular receptor","Enzyme-linked receptor","Ligand-gated ion channel"],0,"β2-adrenergic receptors are GPCRs (7-transmembrane receptors). They couple to Gs protein → activate adenylyl cyclase → ↑cAMP → bronchodilation. Response time: seconds to minutes."),
q("mid144","mid1",L4,"Which type of receptor is correctly associated with INSULIN?",["G protein-coupled receptor","Intracellular receptor","Enzyme-linked receptor (Receptor Tyrosine Kinase)","Ligand-gated receptor"],2,"The insulin receptor is a receptor tyrosine kinase (enzyme-linked receptor). When insulin binds, the receptor undergoes autophosphorylation and activates a kinase cascade. Response time: hours."),
q("mid145","mid1",L4,"Which one of the following is NOT a receptor?",["G-protein coupled receptor","Intracellular receptor","Enzyme-linked receptor","Plasma protein like albumin"],3,"Drug targets include receptors, enzymes, ion channels, and carrier proteins. Plasma proteins like albumin are NOT receptors — they are transport proteins that carry drugs. Binding to albumin produces no pharmacological effect."),
q("mid146","mid1",L4,"An example of a G-protein coupled receptor:",["Nicotinic receptors (ligand-gated ion channel)","B2 adrenergic receptor","Insulin receptor (enzyme-linked)","Steroid receptor (nuclear)"],1,"Receptor types: Ligand-gated ion channels (nicotinic) = milliseconds; GPCRs (muscarinic, β2-adrenergic) = seconds; Kinase-linked (insulin) = hours; Nuclear (steroids) = hours."),
q("mid147","mid1",L4,"Drug A decreases receptor activity, Drug B increases receptor activity, Drug C antagonizes both. What is Drug A?",["Inverse agonist","Partial agonist","Competitive antagonist","Irreversible antagonist"],0,"An inverse agonist has affinity for the receptor but produces the OPPOSITE effect to an agonist — it DECREASES baseline receptor activity below the constitutive level."),
q("mid148","mid1",L4,"On a dose-response graph, Drug D shows a curve furthest to the right compared to A and C. What does this indicate?",["Drug A is less potent than C","Drug A has lower efficacy than B","Drug D shows lower potency than Drugs A and C","Drug D should be administered orally"],2,"Potency is determined by the position along the x-axis (log dose). A curve further to the right = lower potency (more drug needed for same effect). Drug D furthest right = lowest potency."),
q("mid149","mid1",L4,"On a DRC graph, which curve represents PARTIAL AGONIST activity when given alone?",["Curve A — highest Emax","Curve B — submaximal Emax","Curve C — similar to full agonist","Curve D — very low curve"],1,"A partial agonist produces a submaximal response even at maximum concentrations — cannot achieve the full Emax. On a DRC, it plateaus at a LOWER maximum than the full agonist (Curve B)."),
q("mid150","mid1",L5,"When two drugs bind to the same plasma protein binding site, what happens?",["Plasma concentration of displaced drug INCREASES → toxicity","Plasma concentration decreases → treatment failure","No significant change in drug levels","Both drugs become inactive"],0,"When Drug A displaces Drug B from plasma protein binding, Drug B's free (unbound) plasma concentration suddenly increases → more drug available to act → risk of toxicity. Example: aspirin displaces warfarin."),
]

print(f"Mid1 batch 1: {len(mid1)} questions written (1-50)")

mid1 += [
q("mid151","mid1",L5,"Bioavailability of a drug refers to:",["Ratio of oral to parenteral dose","Ratio of administered drug excreted in feces","Percentage of administered dose reaching systemic circulation in unchanged form","Ratio of drug excreted unchanged to metabolites"],2,"Bioavailability (F) = fraction/percentage of an administered dose that reaches the systemic circulation in unchanged (active) form. IV = 100%. Oral BA is reduced by absorption + first-pass metabolism."),
q("mid152","mid1",L5,"What is the definition of bioavailability?",["Fraction of unchanged drug reaching systemic circulation","Proportion of drug reaching circulation in inactive form","Rate of drug absorption from the GI tract","Total amount of drug in the body at any time"],0,"Bioavailability is specifically the fraction of UNCHANGED (active) drug that reaches the systemic circulation, accounting for both absorption and pre-systemic (first-pass) metabolism."),
q("mid153","mid1",L5,"What is the expected effect of FIRST-PASS METABOLISM on bioavailability of an orally taken drug?",["Low bioavailability","High bioavailability","No effect on bioavailability","Variable effect, dose-dependent only"],0,"After oral administration, drugs absorbed from the GI tract pass through the portal vein to the liver before reaching systemic circulation. Liver (and intestinal wall) metabolizes a portion — result: REDUCED bioavailability."),
q("mid154","mid1",L5,"A patient with chronic liver AND renal disease is prescribed propranolol. What is the most appropriate dosing consideration?",["Extensive first-pass metabolism — dose must account for reduced hepatic clearance","Excreted by kidney — dose adjusted for kidney disease only","Short half-life requiring once-daily dosing","Secreted in bile without hepatic modification"],0,"Propranolol has extensive first-pass metabolism. In liver disease, first-pass metabolism is impaired → more drug reaches systemic circulation → risk of toxicity with usual oral doses. Dose reduction required."),
q("mid155","mid1",L5,"The majority of drugs cross biological membranes primarily by:",["Pinocytosis","Passive diffusion","Facilitated diffusion","Active transport"],1,"Passive diffusion is the primary mechanism for most drugs to cross biological membranes. It follows a concentration gradient (high → low), requires no energy, and favors lipophilic, unionized, small MW drugs."),
q("mid156","mid1",L5,"Diffusion of drugs across cell membranes is AFFECTED by:",["Saturation kinetics","Competitive inhibition by related drugs","Dependence on metabolic activity","Extent of ionization of drug molecules"],3,"Passive diffusion depends on lipid solubility and degree of ionization (unionized form diffuses freely; ionized form cannot). Options A, B, C describe ACTIVE TRANSPORT (saturation, inhibition, energy-dependent)."),
q("mid157","mid1",L5,"Which of the following defines DISTRIBUTION?",["The reversible movement of drug between blood and tissues","The irreversible elimination of drug","Drug metabolism in the liver","Excretion of unchanged drug in urine"],0,"Distribution is the reversible process by which a drug leaves the bloodstream and enters body tissues (and can return to blood). Quantified by Volume of Distribution (Vd). Elimination is irreversible."),
q("mid158","mid1",L5,"A drug with a LARGE volume of distribution (Vd) indicates:",["Drug stays in plasma compartment","Excreted rapidly without tissue distribution","Extensively distributed to tissues; low plasma concentration","Poorly absorbed from GI tract"],2,"Vd = Total Amount in Body / Plasma Concentration. Large Vd (>1 L/kg): drug extensively distributed to peripheral tissues → low plasma concentration relative to total body amount. Lipophilic drugs tend to have large Vd."),
q("mid159","mid1",L5,"Drugs that are HIGHLY BOUND to plasma proteins have:",["Large volume of distribution","High bioavailability after oral administration","High renal clearance due to filtration","Greater risk for drug interactions"],3,"Highly protein-bound drugs: small Vd (stay in plasma), low renal clearance (bound drug not filtered), greater drug interaction risk (displacement from binding sites → sudden increase in free fraction → toxicity)."),
q("mid160","mid1",L5,"HIGH plasma protein binding makes a drug:",["Facilitate glomerular filtration","Minimize drug interaction risk","Long-acting (prolonged duration)","Increase volume of distribution"],2,"High protein binding acts as a reservoir — bound drug slowly released as free drug is eliminated → prolongs drug duration. Bound drug is pharmacologically inactive and cannot be filtered by the kidney."),
q("mid161","mid1",L5,"Drug A displaces Drug B from plasma proteins. What happens?",["Decreases effect of Drug B","Increases free fraction of Drug B → increases effect/risk of toxicity","No change in Drug B activity","Increases protein binding of Drug B"],1,"When Drug A displaces Drug B from albumin: Drug B's free (unbound) fraction increases suddenly → more active drug → unexpected toxicity. Example: aspirin displacing warfarin → ↑free warfarin → bleeding risk."),
q("mid162","mid1",L5,"What is expected when warfarin (strongly protein-bound) is given to a patient with SEVERE RENAL IMPAIRMENT?",["No significant change in warfarin levels","Reduced efficacy of warfarin","Increased warfarin free level","Decreased warfarin free level"],2,"In severe renal impairment, uremic toxins accumulate and compete with warfarin for albumin binding sites. Warfarin is displaced from albumin → increased free (unbound) warfarin level → increased bleeding risk."),
q("mid163","mid1",L5,"Phase I metabolism involves:",["Oxidation, reduction, hydrolysis (non-synthetic reactions)","Conjugation only","Glucuronidation only","Synthesis reactions only"],0,"Phase I (non-synthetic): Oxidation, reduction, hydrolysis — primarily via CYP450 enzymes → makes drug more polar, often produces active or toxic metabolites. Phase II (synthetic): conjugation → inactive metabolites for excretion."),
q("mid164","mid1",L5,"What best describes BIOTRANSFORMATION?",["Converts lipid-soluble drug to a non-lipid-soluble (polar) metabolite","Converts drug to more lipid-soluble form","Has no effect on drug activity","Only occurs in the kidney"],0,"The primary goal of biotransformation is to convert lipophilic drugs into more polar (hydrophilic) metabolites that can be renally excreted. Without this, lipophilic drugs would be reabsorbed by renal tubules indefinitely."),
q("mid165","mid1",L5,"Regarding drug metabolism, which statement is CORRECT?",["Metabolism does not occur in plasma or kidneys","Prodrugs don't become active until they are metabolized","Enzyme induction always decreases drug toxicity","Most drugs are metabolized into active metabolites"],1,"Prodrugs are pharmacologically inactive compounds that must undergo metabolic conversion to become active. Examples: codeine → morphine; enalapril → enalaprilat."),
q("mid166","mid1",L5,"Rifampin induces CYP450 enzymes. What is the clinical consequence for a patient taking ORAL CONTRACEPTIVES?",["Increased estrogen levels","Contraceptive failure","No clinically significant effect","Toxicity from estrogen accumulation"],1,"Rifampin is a potent CYP inducer → faster metabolism of oral contraceptives → reduced estrogen/progestin levels → contraceptive failure (unintended pregnancy). Other inducers: carbamazepine, phenytoin, tobacco."),
q("mid167","mid1",L6,"In liver failure, which change is observed?",["Reduced drug half-life","Reduced drug metabolism","Increased plasma protein binding","Increased microsomal enzyme activity"],1,"In liver failure: hepatic metabolism is reduced → drugs accumulate → prolonged half-life. Albumin synthesis also decreases → less protein binding → more free drug. Microsomal enzyme activity is REDUCED."),
q("mid168","mid1",L6,"In liver failure, one of the following changes is observed:",["Microsomal enzyme activity is increased","Half-life of drug is reduced","Metabolism of drug is reduced","Plasma protein binding increases"],2,"Liver failure reduces the liver's ability to metabolize drugs → reduced drug metabolism → drugs accumulate → toxicity risk. Half-life INCREASES (not decreases)."),
q("mid169","mid1",L6,"Patient has hepatitis, cirrhosis, and ascites — which drug must be carefully monitored?",["Erythromycin (hepatically metabolized)","Tobramycin (renally excreted)","Penicillin G (renally excreted)","Furosemide (renally excreted)"],0,"In liver disease, hepatically metabolized drugs accumulate due to impaired hepatic clearance. Erythromycin is metabolized by CYP3A4. Tobramycin and penicillin G are primarily renally excreted."),
q("mid170","mid1",L5,"Zero-order kinetics:",["Constant AMOUNT of drug is eliminated per unit time (not concentration-dependent)","Constant fraction eliminated per unit time","Drug follows first-order kinetics only","Half-life is constant regardless of dose"],0,"Zero-order (saturation) kinetics: elimination rate is constant regardless of concentration (enzymes saturated). No constant t½. Examples: phenytoin, ethanol, aspirin at high doses. First-order: constant fraction eliminated → constant t½."),
q("mid171","mid1",L5,"Drug half-life increases in renal failure. What happens to renally excreted drugs?",["Faster elimination compensates","No change in drug levels","Renally excreted drugs accumulate → toxicity risk","Increased hepatic metabolism compensates"],2,"In renal failure, filtration is impaired → reduced drug clearance → longer half-life → drug accumulation. Critical for drugs like digoxin, aminoglycosides, metformin — require dose reduction."),
q("mid172","mid1",L5,"Which pathway is primarily used for drug elimination?",["Urine (renal excretion)","Sweat","Bile and feces","Saliva"],0,"The kidneys (urine) are the primary route of drug elimination. Polar/water-soluble drugs and metabolites are excreted renally. Bile excretion (fecal route) is secondary. Sweat and saliva are minor routes."),
q("mid173","mid1",L5,"A highly polar drug given to a patient with renal failure would have:",["Reduced clearance","Accumulation of inactive metabolites only","Normal clearance compensated by liver","Increased hepatic metabolism"],0,"Polar (hydrophilic) drugs are excreted by the kidneys via glomerular filtration. In renal failure, GFR is reduced → reduced clearance of polar drugs → drug accumulates → increased toxicity risk."),
q("mid174","mid1",L5,"Factors modifying drug ABSORPTION do NOT include:",["Rate of general (portal) circulation","Hepatic metabolism","Route of administration","Dissolution rate of drug"],1,"Hepatic metabolism affects BIOAVAILABILITY (first-pass effect) but occurs AFTER absorption — it does NOT modify absorption itself. Factors affecting absorption: route, solubility/dissolution, blood flow to site, surface area, GI motility, pH."),
q("mid175","mid1",L5,"Which patient-related factor affects DISTRIBUTION?",["Organ size and perfusion rate","Particle size of drug formulation","Dissolution rate of drug","Drug formulation type"],0,"Distribution depends on patient factors: organ size and blood perfusion (highly perfused organs like liver, kidney, brain receive drug first), plasma protein binding (albumin levels), body composition (fat vs lean). Particle size and dissolution affect ABSORPTION."),
q("mid176","mid1",L6,"ADR Type A (Augmented) is best described as:",["Dose-independent, unpredictable reaction","Dose-dependent, predictable, extension of pharmacological effect","Due to immune mechanism, not dose-related","Occurs only after long-term chronic use"],1,"Type A (Augmented) ADR: dose-dependent, predictable (exaggeration of known pharmacological effect). Most common type (>80% of all ADRs). Preventable by dose reduction. Examples: warfarin → bleeding, insulin → hypoglycemia."),
q("mid177","mid1",L6,"A 60-year-old diabetic presents with sweating, dizziness, blood sugar 65. He took insulin before an unexpected encounter. Type of ADR?",["Type A","Type B","Type C","Type E"],0,"Hypoglycemia from insulin = Type A (Augmented) ADR — extension of the pharmacological effect of insulin (lowering blood sugar), dose-dependent and predictable."),
q("mid178","mid1",L6,"A 67-year-old takes warfarin 12 mg/day (normal 5-10 mg/day) and presents with nasal bleeding. Type of ADR?",["Augmented (Type A)","Bizarre (Type B)","Chronic (Type C)","Delayed (Type D)"],0,"Warfarin-induced bleeding at above-normal dose = Type A (Augmented) ADR — direct, dose-dependent pharmacological extension of warfarin's anticoagulant effect. Predictable and preventable."),
q("mid179","mid1",L6,"Which is an example of an AUGMENTED (Type A) adverse drug reaction?",["Bleeding with warfarin","Cushing syndrome with corticosteroids","Anaphylaxis with penicillin","Peptic ulcer with NSAIDs"],0,"Warfarin-induced bleeding = Type A (dose-dependent extension of anticoagulant effect). Cushing's = Type C (chronic). Anaphylaxis = Type B (bizarre/immunological). NSAIDs peptic ulcer = Type C (chronic)."),
q("mid180","mid1",L6,"A patient with RA takes NSAIDs. After 40 days, develops vomiting, abdominal pain, and gastric ulcer. Type of ADR?",["Type A","Type C (Chronic)","Type B","Type F"],1,"Type C (Chronic/Continuous) ADR: related to cumulative dose + TIME. Develops with long-term use. After 40 DAYS of NSAID use → chronic, time-related → Type C. Other examples: corticosteroids → Cushing's, osteoporosis."),
q("mid181","mid1",L6,"Patient takes NSAIDs and gets gastric ulcer. Type of ADR?",["Type C","Type B","Type D","Type A"],0,"NSAID-induced gastric ulcer = Type C (Chronic) — develops with prolonged use, dose and time dependent. COX-1 inhibition reduces prostaglandin-mediated gastric protection."),
q("mid182","mid1",L6,"A patient takes an antibiotic for surgery. After succinylcholine administration, the patient has prolonged paralysis. Type of ADR?",["Idiosyncratic (Type B)","Pseudoallergic","Allergic Type B","Augmented Type A"],0,"Succinylcholine-induced prolonged paralysis = Type B (Bizarre), specifically idiosyncratic — due to GENETIC variation in pseudocholinesterase. Normal individuals metabolize succinylcholine rapidly; deficient patients cannot."),
q("mid183","mid1",L6,"A newborn has a birth defect of the upper limb; the mother was taking thalidomide during pregnancy. Type of ADR?",["Type D (Delayed — teratogenesis)","Type C (Chronic)","Type B (Bizarre)","Type F (Failure)"],0,"Type D (Delayed) ADR: adverse effects that occur AFTER treatment ends, including teratogenesis, carcinogenesis. Thalidomide caused phocomelia (limb defects) in infants whose mothers took it in the first trimester."),
q("mid184","mid1",L6,"What is the cause of the thalidomide-phocomelia syndrome?",["Teratogenicity","Pharmacological interaction","Allergic reaction","Enzyme inhibition"],0,"Thalidomide interferes with limb bud development during the critical embryonic period (weeks 4-8 of gestation) via inhibition of angiogenesis → teratogenicity (Category X drug)."),
q("mid185","mid1",L6,"A drug taken in the first trimester causes limb defects. It is classified as:",["Category A","Category B","Teratogen (Category D or X)","Category C only"],2,"A drug causing limb defects in the 1st trimester is a TERATOGEN. Category X is absolutely contraindicated (risks always outweigh benefits). Category D has evidence of fetal risk but benefits may outweigh risks in severe disease."),
q("mid186","mid1",L6,"A 27-year-old becomes pregnant. She was taking warfarin (Category D) and amoxicillin (Category B). What should you do?",["Keep warfarin, change amoxicillin","Keep amoxicillin, change warfarin to a safer anticoagulant","Keep both drugs","Stop both drugs immediately"],1,"Warfarin (Category D) causes embryopathy and fetal hemorrhage — replace with LMWH (heparin doesn't cross the placenta). Amoxicillin (Category B) has no fetal risk — safe to continue."),
q("mid187","mid1",L6,"IDIOSYNCRASY is:",["A type of receptor antagonism","A type B adverse effect (genetic/unusual reaction)","Normal pharmacological response to overdose","Drug tolerance"],1,"Idiosyncrasy = a genetically-determined abnormal/unusual response to a drug. Classified as Type B (Bizarre) ADR. Not dose-related, not predictable from pharmacology. Examples: G6PD deficiency → hemolysis with primaquine."),
q("mid188","mid1",L6,"An asthmatic patient is given a non-selective β-agonist. What adverse effect would you expect?",["Tachycardia","Bradycardia","Hypotension","Bronchoconstriction"],0,"Non-selective β-agonist stimulates both β1 (cardiac) → tachycardia (unwanted) and β2 (bronchial) → bronchodilation (desired). Selective β2-agonists (salbutamol) are preferred in asthma to avoid cardiac side effects."),
q("mid189","mid1",L6,"Which of the following is a common adverse effect of AMPHETAMINES?",["Bradycardia","Somnolence","Constipation","Hypertension"],3,"Amphetamines are sympathomimetics that release norepinephrine and dopamine. Typical adverse effects: hypertension, tachycardia, hyperthermia, tremor, insomnia, agitation. NOT bradycardia or somnolence."),
q("mid190","mid1",L6,"A patient with succinylcholine prolonged apnea in surgery — type of adverse reaction?",["Idiosyncratic (Type B)","Pseudoallergic reaction","True allergic reaction","Augmented pharmacological reaction"],0,"Same mechanism as prolonged paralysis — pseudocholinesterase deficiency prevents succinylcholine metabolism → prolonged neuromuscular blockade/apnea. Idiosyncratic Type B reaction due to genetic enzyme deficiency."),
q("mid191","mid1",L6,"Which of the following is LEAST likely to pass through the placenta and harm the fetus?",["Hydrophilic and high molecular weight","Hydrophilic and low molecular weight","Lipophilic and high molecular weight","Lipophilic and low molecular weight"],0,"The placental barrier behaves like a lipid membrane. Drugs crossing easily: lipophilic, low MW, un-ionized. Therefore, hydrophilic + high MW = LEAST likely to cross the placenta and harm the fetus."),
q("mid192","mid1",L7,"Warfarin taken with CIPROFLOXACIN causes:",["Hypoglycemia","No clinically significant interaction","Reduced bleeding risk","Increased bleeding risk"],3,"Ciprofloxacin is a CYP450 inhibitor (CYP1A2, partially CYP2C9). It inhibits warfarin metabolism → increased warfarin plasma levels → increased anticoagulant effect → increased bleeding risk."),
q("mid193","mid1",L7,"ANTACIDS reduce the absorption of:",["Insulin","Warfarin","Tetracycline","Heparin"],2,"Antacids (containing Al³⁺, Mg²⁺, Ca²⁺) form insoluble chelate complexes with tetracycline, preventing GI absorption. Tetracycline should be taken 2 hours before or 4-6 hours after antacids."),
q("mid194","mid1",L7,"A patient with cutaneous anthrax is prescribed ciprofloxacin. Which should he AVOID taking with it?",["Alcohol","Grapefruit juice","Antacid","Dairy products"],2,"Antacids chelate quinolone antibiotics (ciprofloxacin) via their divalent/trivalent metal ions (Mg²⁺, Al³⁺, Ca²⁺), significantly reducing absorption. Must be separated by at least 2 hours."),
q("mid195","mid1",L8,"A farmer develops excessive sweating, vomiting, and salivation after work. What is the antidote?",["PAM (pralidoxime) and atropine","Naloxone","N-acetylcysteine","Deferoxamine"],0,"Symptoms (SLUDGE: Salivation, Lacrimation, Urination, Defecation, GI distress, Emesis) = organophosphate (cholinergic) toxidrome. Treatment: Atropine (muscarinic antagonist) + Pralidoxime (reactivates AChE if given early)."),
q("mid196","mid1",L7,"What is the drug that has to be dose-adjusted when given with allopurinol?",["Mercaptopurine (6-MP)","Methotrexate","Azithromycin","Cyclophosphamide"],0,"Allopurinol inhibits xanthine oxidase, the enzyme responsible for metabolizing mercaptopurine (6-MP) and azathioprine. Co-administration → toxic accumulation. Dose of 6-MP must be reduced to 25-33%."),
q("mid197","mid1",L6,"Prolonged use of phenylephrine as a nasal decongestant results in:",["Epistaxis","Atrophic rhinitis (rhinitis medicamentosa)","Chronic cough","Hypertrophy of nasal mucosa"],1,"Prolonged use of vasoconstrictive nasal decongestants causes rebound congestion (rhinitis medicamentosa) and with long-term use → atrophic rhinitis (thinning and atrophy of nasal mucosa). Type C (chronic) ADR."),
q("mid198","mid1",L7,"A patient was on sulfonamide causing crystalluria. How can we avoid this?",["Decrease fluid intake","Add folinic acid supplement","Alkalization of urine","Increase drug concentration"],2,"Sulfonamides can crystallize in urine (crystalluria) → renal tubular obstruction. Prevention: alkalinize the urine (sodium bicarbonate — sulfonamides more soluble at alkaline pH) + adequate hydration."),
q("mid199","mid1",L7,"A pregnant woman is taking sulfonamide. What is the potential danger to the neonate?",["Kernicterus","Hepatotoxicity in neonate","Nephrotoxicity in neonate","Bone marrow suppression"],0,"Sulfonamides in pregnancy (especially near term) can cause kernicterus — sulfonamides displace bilirubin from plasma protein binding in the neonate → unconjugated bilirubin enters the brain → neurotoxicity."),
q("mid1100","mid1",L7,"A doctor wants to give chloramphenicol to a neonate. What would INCREASE the risk of gray baby syndrome?",["Decreasing conjugation in the liver","Decreasing renal excretion only","Increasing drug dose only","Using IM route instead of IV"],0,"Neonates have immature hepatic glucuronyl transferase — cannot conjugate chloramphenicol effectively. Decreasing conjugation (as in immature neonatal liver) further increases accumulation → gray baby syndrome (cardiovascular collapse)."),
]

